package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testIsNullStringSet_whenNullStringIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to set the private final field nullString to null
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);

        // Remove final modifier
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(nullStringField, nullStringField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        nullStringField.set(format, null);

        boolean result = format.isNullStringSet();
        assertFalse(result, "Expected isNullStringSet to return false when nullString is null");
    }

    @Test
    public void testIsNullStringSet_whenNullStringIsNotNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to set the private final field nullString to "NULL"
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);

        // Remove final modifier
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(nullStringField, nullStringField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        nullStringField.set(format, "NULL");

        boolean result = format.isNullStringSet();
        assertTrue(result, "Expected isNullStringSet to return true when nullString is not null");
    }
}
